const scuba2 = L.polygon(scuba2_beams,{color:"#ffffff", fillOpacity:0, weight:1},);


// Basic map setup =============================================================
L.CRS.FitsMap = L.extend({}, L.CRS.Simple, {
    transformation: new L.Transformation(1/256, 0, -1/256, 256)
});

const map = L.map("map", {
    crs: L.CRS.FitsMap,
    minZoom: 0,
    preferCanvas: true,
    layers: [f444w],
    zoomControl: false  // Disable default zoom control
});

// Custom Back Button Control
L.Control.BackButton = L.Control.extend({
    options: {
        position: 'topleft'
    },
    onAdd: function(map) {
        var container = L.DomUtil.create('div', 'leaflet-bar leaflet-control-back');
        var button = L.DomUtil.create('a', 'leaflet-control-back-button', container);
        
        button.href = '../nircam-cosmos.html';
        button.innerHTML = '<svg width="12" height="12" viewBox="0 0 12 12"><path d="M8 2 L4 6 L8 10" stroke="currentColor" stroke-width="2" fill="none" stroke-linecap="round" stroke-linejoin="round"/></svg>';
        button.title = 'Back to NIRCam COSMOS page';
        
        L.DomEvent.disableClickPropagation(button);
        L.DomEvent.on(button, 'click', function(e) {
            L.DomEvent.preventDefault(e);
            window.location.href = this.href;
        }, button);
        
        return container;
    }
});

// Add back button FIRST
const backButton = new L.Control.BackButton();
backButton.addTo(map);

// Add zoom control AFTER back button
L.control.zoom({
    position: 'topleft'
}).addTo(map);

const helpControl = L.control.help({
    position:"topleft",
    title: "About ",
    content: `
    <p>
    Nothing yet.
    </p>
`
});
helpControl.addTo(map);

const coordSearch = L.control.coordsearch({
    position:"topleft",
    default: "RA Dec [Zoom]",
});
coordSearch.addTo(map);
coordSearch.enable();

const layerControl = L.control.layers(
    {
        "NIRCam F444W (SNR)": f444w,
    },
    {}
).addTo(map);

const regionControl = L.control.layers(
    {},
    {'COSMOS-Web Tiles':tiles, 
     'PRIMER NIRCam':primer_nircam_outline, 
     'COSMOS-3D NIRCam':c3d_nircam,
     'COSMOS-3D MIRI':c3d_miri,
     'SCUBA-2':scuba2}
).addTo(map);

