// Map event setup =============================================================
f444w.on("load", () => {
    document.getElementById("loading-screen").style.visibility = "hidden";
    document.getElementById("map").style.visibility = "visible";
});


map.whenReady(function(){
    document.getElementsByClassName("leaflet-control-layers-base")[0].prepend('Images');
    document.getElementsByClassName("leaflet-control-layers-overlays")[1].prepend("Regions");
    // document.getElementsByClassName("leaflet-control-layers-overlays")[2].prepend("Catalogs");
});


map.on("moveend", updateLocationBar);
map.on("zoomend", updateLocationBar);

if (urlParam("zoom")==null) {
    map.fitBounds(L.latLngBounds([[0, 0], [57636, 59355]]));
} else {
    panFromUrl(map);
}

const f444w_mini = L.tileLayer("../data/fitsmaps/cosmos/mosaic_nircam_f444w_cosmos_60mas_v0p7_full_nsci/{z}/{y}/{x}.png", { attribution:"<a href='https://github.com/ryanhausen/fitsmap'>FitsMap</a>", minZoom: 0, maxZoom: 13, maxNativeZoom: 8});
var miniMap = new L.control.minimap(f444w_mini,
    {position: 'bottomright', 
    width: 220, 
    height: 220,
    zoomLevelFixed: 0,
    toggleDisplay: true,
    autoToggleDisplay: true,
    minimized: true,
    centerFixed: L.latLng(28818, 29677.5)
    }
).addTo(map);

